// 性能监控实现
function monitorPerformance<T>(operation: string, fn: () => T): T {
  const start = Date.now();
  try {
    const result = fn();
    const end = Date.now();
    console.debug(`[mem:perf] ${operation}: ${end - start}ms`);
    return result;
  } catch (error) {
    const end = Date.now();
    console.error(`[mem:perf] ${operation} 失败: ${end - start}ms`, error);
    throw error;
  }
}
